#include <stdio.h>
void inc(int n) { n = n + 1; }
int main() {
    int x = 10;
    inc(x);
    printf("%d", x);
    return 0;
}

#include <stdio.h>
void swap(int *a, int *b) { int t = *a; *a = *b; *b = t; }
int main() {
    int x = 3, y = 7;
    swap(&x, &y);
    printf("%d %d", x, y);
    return 0;
}
